// nodes/BaseNode.js
// Reusable node abstraction — all nodes are built from this.

import { Handle, Position } from 'reactflow';

/**
 * BaseNode
 *
 * Props:
 *   id          — node id from ReactFlow
 *   data        — node data object
 *   title       — node title string
 *   icon        — emoji or character shown in header
 *   accentColor — hex color for the left border accent
 *   inputs      — array of handle config objects:  { id, label, position? (0..1) }
 *   outputs     — array of handle config objects:  { id, label, position? (0..1) }
 *   children    — body content (fields, selects, etc.)
 *   minWidth    — optional minimum width in px (default 220)
 *   style       — optional extra style overrides for wrapper
 */
export const BaseNode = ({
  id,
  title,
  icon,
  accentColor = '#6366f1',
  inputs = [],
  outputs = [],
  children,
  minWidth = 220,
  style = {},
}) => {
  return (
    <div
      style={{
        minWidth,
        background: 'linear-gradient(145deg, #1a1f2e, #161b28)',
        border: '1px solid rgba(255,255,255,0.08)',
        borderLeft: `3px solid ${accentColor}`,
        borderRadius: '10px',
        boxShadow: `0 4px 24px rgba(0,0,0,0.4), 0 0 0 0.5px rgba(255,255,255,0.04)`,
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
        position: 'relative',
        ...style,
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          padding: '10px 14px 8px',
          borderBottom: '1px solid rgba(255,255,255,0.06)',
        }}
      >
        {icon && (
          <span style={{ fontSize: '14px', lineHeight: 1 }}>{icon}</span>
        )}
        <span
          style={{
            fontSize: '11px',
            fontWeight: 700,
            letterSpacing: '0.08em',
            textTransform: 'uppercase',
            color: accentColor,
          }}
        >
          {title}
        </span>
      </div>

      {/* Body */}
      <div style={{ padding: '10px 14px 12px' }}>{children}</div>

      {/* Input handles */}
      {inputs.map((handle, i) => {
        const top = inputs.length === 1
          ? '50%'
          : `${10 + (handle.position ?? i / (inputs.length - 1)) * 80}%`;
        return (
          <div key={handle.id}>
            <Handle
              type="target"
              position={Position.Left}
              id={handle.id}
              style={{
                top,
                left: -6,
                width: 12,
                height: 12,
                background: accentColor,
                border: '2px solid #1a1f2e',
                borderRadius: '50%',
              }}
            />
            {handle.label && (
              <span
                style={{
                  position: 'absolute',
                  left: 10,
                  top,
                  transform: 'translateY(-50%)',
                  fontSize: '9px',
                  color: 'rgba(255,255,255,0.4)',
                  pointerEvents: 'none',
                  whiteSpace: 'nowrap',
                }}
              >
                {handle.label}
              </span>
            )}
          </div>
        );
      })}

      {/* Output handles */}
      {outputs.map((handle, i) => {
        const top = outputs.length === 1
          ? '50%'
          : `${10 + (handle.position ?? i / (outputs.length - 1)) * 80}%`;
        return (
          <div key={handle.id}>
            <Handle
              type="source"
              position={Position.Right}
              id={handle.id}
              style={{
                top,
                right: -6,
                width: 12,
                height: 12,
                background: accentColor,
                border: '2px solid #1a1f2e',
                borderRadius: '50%',
              }}
            />
            {handle.label && (
              <span
                style={{
                  position: 'absolute',
                  right: 10,
                  top,
                  transform: 'translateY(-50%)',
                  fontSize: '9px',
                  color: 'rgba(255,255,255,0.4)',
                  pointerEvents: 'none',
                  whiteSpace: 'nowrap',
                  textAlign: 'right',
                }}
              >
                {handle.label}
              </span>
            )}
          </div>
        );
      })}
    </div>
  );
};

// Shared field styles used by all nodes
export const fieldStyle = {
  label: {
    display: 'block',
    fontSize: '10px',
    fontWeight: 600,
    letterSpacing: '0.06em',
    textTransform: 'uppercase',
    color: 'rgba(255,255,255,0.45)',
    marginBottom: '4px',
  },
  input: {
    width: '100%',
    background: 'rgba(255,255,255,0.05)',
    border: '1px solid rgba(255,255,255,0.1)',
    borderRadius: '6px',
    padding: '6px 9px',
    fontSize: '12px',
    color: '#e2e8f0',
    outline: 'none',
    boxSizing: 'border-box',
    transition: 'border-color 0.15s',
  },
  select: {
    width: '100%',
    background: 'rgba(255,255,255,0.05)',
    border: '1px solid rgba(255,255,255,0.1)',
    borderRadius: '6px',
    padding: '6px 9px',
    fontSize: '12px',
    color: '#e2e8f0',
    outline: 'none',
    boxSizing: 'border-box',
    cursor: 'pointer',
  },
  group: {
    marginBottom: '10px',
  },
};
